import{_ as e,o,c as t,ag as s}from"./chunks/framework.CYCRomDB.js";const a=JSON.parse('{"title":"what\'s SEO","description":"網路、資訊上目前頗重要的一件事 SEO(Search Engine Optimization) 中文為 搜尋引擎最佳化 那這個東西是什麼? 能吃? 能用? 能有什麼幫助呢? 簡單說明 SEO... 如上圖所示, 在Google 搜尋iphone6s, 所得到的搜尋結果...","frontmatter":{"title":"what\'s SEO","date":"2026-03-01T00:00:00.000Z","updated":"2026-03-02T00:00:00.000Z","description":"網路、資訊上目前頗重要的一件事 SEO(Search Engine Optimization) 中文為 搜尋引擎最佳化 那這個東西是什麼? 能吃? 能用? 能有什麼幫助呢? 簡單說明 SEO... 如上圖所示, 在Google 搜尋iphone6s, 所得到的搜尋結果...","author":"Cola","tags":["SEO"],"keywords":["SEO","php","seo"],"readingTime":"7 min read","readingMinutes":7,"permalink":"/whats-seo","slug":"whats-seo","issueId":5,"githubUrl":"https://github.com/cscolabear/cscolabear.github.io/issues/5"},"headers":[],"relativePath":"whats-seo.md","filePath":"posts/whats-seo.md","lastUpdated":1773042602000}');const r=e({name:"whats-seo.md"},[["render",function(e,a,r,l,i,n){return o(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="what-s-seo" tabindex="-1">what&#39;s SEO <a class="header-anchor" href="#what-s-seo">#</a></h1><p><img src="https://github.com/user-attachments/assets/d595ab6a-b812-4ff9-8d71-7c0a23d5c6a7" alt="Image"></p><p>網路、資訊上目前頗重要的一件事</p><p><strong>SEO</strong>(Search Engine Optimization)</p><p>中文為 <strong>搜尋引擎最佳化</strong></p><p>那這個東西是什麼? 能吃? 能用? 能有什麼幫助呢?</p><hr><h2 id="簡單說明-seo" tabindex="-1"><strong>簡單說明 SEO...</strong> <a class="header-anchor" href="#簡單說明-seo">#</a></h2><p><img src="https://github.com/user-attachments/assets/47b88fff-9a4b-45b6-bc03-9ff374296f51" alt="Image"></p><p>如上圖所示, 在Google 搜尋<a href="https://www.google.com.tw/webhp?sourceid=chrome-instant&amp;ion=1&amp;espv=2&amp;es_th=1&amp;ie=UTF-8#q=iphone6s" target="_blank" rel="noreferrer">iphone6s</a>, 所得到的搜尋結果... 這樣的搜尋結果<strong>排序內容</strong>, 就被稱為 SEO</p><p>使用者所用的<strong>關鍵字</strong>在Google得到的<strong>排序結果\b</strong></p><p>你的網站會被Google被放在什麼樣的位置,第幾頁.... 透過一些手法、方式去變動、影響、調整的技術就被稱為 SEO，主要的目的是<strong>針對目標關鍵字，調整搜尋結果的排序位置!</strong></p><p></p><p>當然，如圖內的紅框 我們也可以透過購買Google 廣告的方式, 讓自已的網站排在最上面, 但SEO主要是透過<strong>非廣告</strong>的方式去調整排序位置\b</p><p></p><p></p><p><img src="https://github.com/user-attachments/assets/6f74fafa-519e-4bc1-8952-70fd2b553972" alt="Image"></p><p>可以看見<a href="https://www.google.com.tw/webhp?sourceid=chrome-instant&amp;ion=1&amp;espv=2&amp;es_th=1&amp;ie=UTF-8#q=iphone6s" target="_blank" rel="noreferrer">iphone6s</a>這樣的關鍵字, 可以找到的結果10頁之多... (<a href="#diff-search">註：搜尋結果不同?</a>)</p><hr><h2 id="google-怎麼提供-製作搜尋結果和怎麼排序網站" tabindex="-1"><strong>Google 怎麼提供，製作搜尋結果和怎麼排序網站?</strong> <a class="header-anchor" href="#google-怎麼提供-製作搜尋結果和怎麼排序網站">#</a></h2><p>簡單來講Google 會利用<strong>網站爬蟲</strong>(註.<a href="#crawler">Google 爬蟲的運作方式</a>)取得網路上大部份的網站資料\b, 處理為<strong>大數據後(Big Data)</strong>, 提供給使用者 接者Google會利用幾種方式排序搜尋結果....</p><ul><li>網站內容 SEO 主要調整的部份</li><li>網站速度 速度太慢的網站, 使用者也不會等待, 太浪費時間了</li><li>網站流量、點擊量 人為傳播 - 愈多人使用的網站，排序結果愈好(殘酷的現實是....., 10人流量而提供正確訊息的網站，也比不上有1000人使用而提供錯誤訊息的網站...)</li><li>網站曝光率 若你的網站常常在 Yahoo, 或是各大新聞網站出現, Google 就會認為你的網站內容是熱門、有用的，簡單說就是<strong>利用更熱門的網站來拉升你的網站</strong></li></ul><p>當然還有其它更多影響因素....</p><hr><h2 id="怎麼做seo" tabindex="-1"><strong>怎麼做SEO?</strong> <a class="header-anchor" href="#怎麼做seo">#</a></h2><p>SEO的手法中有分白帽SEO(white hat)與黑帽SEO(black hat) 兩種, 這次先不談這個較麻煩的問題... (註:<a href="#black-hat">不合法的SEO方式 - 黑帽SEO，優點與缺點</a>)</p><p>第一步的<strong>Check List</strong></p><ul><li>向Google 主動提交網站 <a href="https://www.google.com.tw/webmasters/" target="_blank" rel="noreferrer">Google 網站管理員</a></li><li>修改 HTML META 標籤資料(keyword,description)</li><li>確認 robots.txt - <a href="https://support.google.com/webmasters/answer/6062608?hl=zh-Hant" target="_blank" rel="noreferrer">Google Robots.txt</a></li><li>Sitemap 頁的製作</li></ul><p>網站SEO是一條漫長的路, 第一步處理完之後還可以依據後續結果和數據再做調整，<strong>整個 SEO 過程就是不斷的修改與調整，達到最佳目標!</strong></p><p>(更詳細的Checklist, 可以看看 <a href="http://cola.workxplay.net/first-steps-to-seo/" target="_blank" rel="noreferrer">SEO第一步該做什麼? SEO的第一步</a>)</p><hr><p>註釋：</p><h3 id="搜尋結果不同" tabindex="-1"><strong>搜尋結果不同?</strong> <a class="header-anchor" href="#搜尋結果不同">#</a></h3><p>在Goole 搜尋結果會依很多種原因、因素而變動 影響因素包含</p><ul><li>網路上出現<strong><strong>更好的資料內容</strong></strong></li><li>你的網站包含了不被Goolge 接受的資料(<strong>非法SEO手段</strong>、盜版或是盜用內容)</li><li>你本身的<strong>搜尋習慣與記錄</strong> 這是個很重要的問題, 大家都常會在同一個瀏覽器上做許多搜尋動作 所有的查詢動作, 你的網站瀏覽習慣都會被 Google 記錄下來, 好讓 Google 提供你,他覺得對你較好的結果... 簡單例如說：你常常在巴哈姆特Gamer 查詢遊戲攻略, Google 自然會把巴哈姆特中相關的內容提供給你, 這樣的動作對個人使用者是好的, 因為更高的可能性是你想要的答案. 但是對網站經營者而言不是件好事...., 這樣的搜尋結果沒有公正性, 也不客觀!</li></ul><p></p><h3 id="不合法的seo方式-黑帽-seo-優點與缺點" tabindex="-1"><strong>不合法的SEO方式 - 黑帽 SEO，優點與缺點</strong> <a class="header-anchor" href="#不合法的seo方式-黑帽-seo-優點與缺點">#</a></h3><p>利用作弊的手法做 SEO，讓網站在Goole 那邊取得更好的排名結果 但是好與不好之間還是有些尷尬點存在...Google 也很難100%判斷對錯!! 優點：</p><ul><li>快速讓搜尋排名爬升</li><li>快速增加曝光率</li><li>和競爭對手用相同的內容，卻能讓排名<strong>暴力提升</strong></li></ul><p>缺點：</p><ul><li>對使用者很噁心, 內容醜惡</li><li>包含了垃圾訊息在網站中</li><li>整個網站隨時都有被 Google <strong>永不收錄</strong>的可能</li></ul><p></p><h3 id="google-爬蟲的運作方式" tabindex="-1"><strong>Google 爬蟲的運作方式</strong> <a class="header-anchor" href="#google-爬蟲的運作方式">#</a></h3><p>Google如何知道網站的內容? 他們會利用程式, 機器人, 也是網站爬蟲/Crawler/google robot, 取得網路上大部份的網站資料、內容進行處理 流程大至上為....</p><ol><li>得知有一個網站(人為傳播, 主動告知) 在文章前面有提到 - 人為傳播, 可以讓Google 知道有這個網站的存在, 若是網站是新上線, 完全沒有曝光過則可以透過 Google 提供的服務 主動告知 - <a href="https://www.google.com.tw/webmasters/" target="_blank" rel="noreferrer">Google 網站管理員</a></li><li>打開 sitemap 內容 sitemap = 網站地圖, 一個頁面或是一個檔案, 內容包含整個網站所有連結、網址</li><li>打開網頁 網站的速度, 決定爬蟲要花多少時間處理你的網站, 速度愈慢, 被Google 處理的慾望愈低 lol</li><li>解析HTML標籤, 等內容 正確, 沒有錯誤的 HTML標籤能讓機器人/爬蟲瞭解你的內容</li></ol><hr><h2 id="💬-留言討論-1-則" tabindex="-1">💬 留言討論 (1 則) <a class="header-anchor" href="#💬-留言討論-1-則">#</a></h2><div class="comment-card"><div class="comment-header"><strong>@cscolabear</strong><span class="comment-date">2026/3/2 上午04:01</span></div><p>舊文<br> 待調整排版~</p></div><hr><div class="github-discussion"><a href="https://github.com/cscolabear/cscolabear.github.io/issues/5" target="_blank" rel="noopener noreferrer"> 💬 在 GitHub 上討論這篇文章 </a></div>',50)])])}]]);export{a as __pageData,r as default};
